-- ══════════════════════════════════════════════════════════════
-- Tabela: cadastros_atak
-- 381 Fornecedores + 78 Motoristas do WRCAD009
-- (transportadores excluídos — gerenciados pela Trans Anacleto)
-- Rodar no SQL Editor do Supabase
-- ══════════════════════════════════════════════════════════════

CREATE TABLE IF NOT EXISTS cadastros_atak (
  id        UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  codigo    TEXT NOT NULL UNIQUE,
  nome      TEXT NOT NULL,
  apelido   TEXT,
  cnpj      TEXT,
  uf        TEXT,
  tipo      TEXT NOT NULL CHECK (tipo IN ('fornecedor','motorista')),
  ativo     BOOLEAN DEFAULT true,
  criado_em TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_cadastros_tipo   ON cadastros_atak(tipo);
CREATE INDEX IF NOT EXISTS idx_cadastros_uf     ON cadastros_atak(uf);
CREATE INDEX IF NOT EXISTS idx_cadastros_codigo ON cadastros_atak(codigo);

ON CONFLICT (codigo) DO UPDATE SET
  nome    = EXCLUDED.nome,
  apelido = EXCLUDED.apelido,
  cnpj    = EXCLUDED.cnpj,
  uf      = EXCLUDED.uf;

-- Verificação
SELECT tipo, COUNT(*) FROM cadastros_atak GROUP BY tipo;